




                    document.addEventListener('DOMContentLoaded', function () {
                        // We add a small delay to ensure all assets/fonts are loaded before Slick calculates widths
                        setTimeout(function () {
                            if (window.jQuery && window.jQuery.fn.slick) {
                                window.jQuery('#product-slider').slick({
                                    dots: true,
                                    infinite: true,
                                    speed: 500,
                                    slidesToShow: 3,
                                    slidesToScroll: 1,
                                    autoplay: true,
                                    autoplaySpeed: 3000,
                                    rtl: true,
                                    prevArrow: window.jQuery('#prev-prod'),
                                    nextArrow: window.jQuery('#next-prod'),
                                    responsive: [{
                                        breakpoint: 1024,
                                        settings: {
                                            slidesToShow: 2,
                                            slidesToScroll: 1
                                        }
                                    },
                                    {
                                        breakpoint: 640,
                                        settings: {
                                            slidesToShow: 1,
                                            slidesToScroll: 1
                                        }
                                    }
                                    ]
                                });
                            }
                        }, 150);
                    });
                

                    document.addEventListener('DOMContentLoaded', function () {
                        setTimeout(function () {
                            if (window.jQuery && window.jQuery.fn.slick) {
                                let $slider = window.jQuery('#branch-slider');

                                $slider.slick({
                                    vertical: true,
                                    verticalSwiping: true,
                                    slidesToShow: 3,
                                    slidesToScroll: 1,
                                    autoplay: true,
                                    autoplaySpeed: 0,
                                    speed: 4000,
                                    cssEase: 'linear',
                                    arrows: false,
                                    dots: false,
                                    infinite: true,
                                    pauseOnHover: true,
                                    rtl: false,
                                    responsive: [
                                        { breakpoint: 1024, settings: { slidesToShow: 2 } },
                                        { breakpoint: 640, settings: { slidesToShow: 2 } }
                                    ]
                                });

                                // Sync map
                                $slider.on('beforeChange', function (event, slick, currentSlide, nextSlide) {
                                    let $nextSlide = window.jQuery(slick.$slides[nextSlide]);
                                    let branchId = $nextSlide.find('.branch-card').attr('data-branch-id');
                                    window.dispatchEvent(new CustomEvent('branch-changed', { detail: parseInt(branchId) }));
                                });

                                // Physical position based highlighting
                                // This guarantees the card closest to the top is colored, even if it's a clone!
                                setInterval(function () {
                                    let $list = window.jQuery('#branch-slider .slick-list');
                                    if ($list.length === 0) return;

                                    let containerTop = $list.offset().top;
                                    let $bestSlide = null;
                                    let minDiff = 99999;

                                    window.jQuery('#branch-slider .slick-slide').each(function () {
                                        let topOffset = window.jQuery(this).offset().top - containerTop;
                                        // Find the slide that is physically at the top position
                                        if (topOffset > -100 && topOffset < 150) {
                                            if (Math.abs(topOffset) < minDiff) {
                                                minDiff = Math.abs(topOffset);
                                                $bestSlide = window.jQuery(this);
                                            }
                                        }
                                    });

                                    if ($bestSlide && $bestSlide.length > 0) {
                                        let $card = $bestSlide.find('.branch-card');

                                        if (!$card.hasClass('active-state-applied')) {
                                            // Remove from all cards (original and clones)
                                            window.jQuery('.branch-card').removeClass('is-active-card is-active-main active-state-applied');

                                            // Apply exactly to this single DOM element
                                            $card.addClass('active-state-applied');
                                            if ($card.attr('data-branch-id') == "1") {
                                                $card.addClass('is-active-main');
                                            } else {
                                                $card.addClass('is-active-card');
                                            }
                                        }
                                    }
                                }, 50);
                            }
                        }, 150);
                    });
                

